const fs = require\('fs'\);
const content = fs.readFileSync\('D:/raxlarchitects/assets/index-BUkr1E8S.js', 'utf8'\);

// Check for various problematic characters
const problemRanges = [
  { name: 'Smart quotes', start: 0x2018, end: 0x201F },
  { name: 'Single smart quotes', start: 0x2018, end: 0x201B },
  { name: 'Double smart quotes', start: 0x201C, end: 0x201D },
  { name: 'Low quotes', start: 0x201A, end: 0x201B },
];

const allProblems = [];
for \(let i = 0; i < Math.min\(content.length, 250000\); i++\) {
  const code = content.charCodeAt\(i\);
  for \(const range of problemRanges\) {
    if \(code >= range.start && code <= range.end\) {
      allProblems.push\({ code, pos: i, char: String.fromCharCode\(code\), range: range.name }\);
      break;
    }
  }
}

// Count by character
const counts = {};
allProblems.forEach\(p => {
  counts[p.code] = \(counts[p.code] || 0\) + 1;
}\);

console.log\('Problematic characters still found:'\);
for \(const [code, count] of Object.entries\(counts\)\) {
  console.log\('  U+' + parseInt\(code\).toString\(16\).toUpperCase\(\).padStart\(4, '0'\) + ':', count, 'occurrences'\);
}

if \(allProblems.length > 0 && allProblems.length < 20\) {
  console.log\('\\nDetails:'\);
  allProblems.forEach\(\(p, i\) => {
    console.log\(i, 'U+' + p.code.toString\(16\).toUpperCase\(\).padStart\(4, '0'\), 'at', p.pos, '-' + p.range\);
