const fs = require\('fs'\);
const content = fs.readFileSync\('D:/raxlarchitects/assets/index-BUkr1E8S.js', 'utf8'\);

// Check for control characters and unusual encoding
const unusual = [];
for \(let i = 0; i < Math.min\(content.length, 50000\); i++\) {
  const code = content.charCodeAt\(i\);
  // Control characters except \\t, \\n, \\r
  if \(code < 32 && code !== 9 && code !== 10 && code !== 13\) {
    unusual.push\({ code, pos: i, name: 'control' }\);
  }
  // UTF-16 surrogate pairs and special
  if \(code >= 0xD800 && code <= 0xDFFF\) {
    unusual.push\({ code, pos: i, name: 'surrogate' }\);
  }
}

console.log\('Unusual characters found:', unusual.length\);
if \(unusual.length > 0\) {
  unusual.slice\(0, 10\).forEach\(\(p, i\) => {
    console.log\(i, 'Code:', p.code, 'Position:', p.pos, 'Type:', p.name\);
  }\);
}

// Also check for malformed UTF-8 in buffer
const buf = fs.readFileSync\('D:/raxlarchitects/assets/index-BUkr1E8S.js'\);
let invalidUtf8 = 0;
for \(let i = 0; i < buf.length; i++\) {
  const b = buf[i];
  if \(b > 127\) {
    // Check if valid UTF-8 continuation
    if \(\(b & 0xE0\) === 0xC0\) { // 2-byte sequence
      if \(i + 1 >= buf.length || \(buf[i + 1] & 0xC0\) !== 0x80\) invalidUtf8++;
    } else if \(\(b & 0xF0\) === 0xE0\) { // 3-byte sequence
      if \(i + 2 >= buf.length || \(buf[i + 1] & 0xC0\) !== 0x80 || \(buf[i + 2] & 0xC0\) !== 0x80\) invalidUtf8++;
    } else if \(\(b & 0xF8\) === 0xF0\) { // 4-byte sequence
      if \(i + 3 >= buf.length || \(buf[i + 1] & 0xC0\) !== 0x80 || \(buf[i + 2] & 0xC0\) !== 0x80 || \(buf[i + 3] & 0xC0\) !== 0x80\) invalidUtf8++;
    } else if \(b < 0x80 || b > 0xBF\) {
      // Invalid continuation byte or invalid start byte
      if \(\(b & 0xC0\) !== 0x80\) invalidUtf8++;
    }
  }
}
console.log\('Invalid UTF-8 sequences:', invalidUtf8\);
