const fs = require\('fs'\);
const vm = require\('vm'\);

const content = fs.readFileSync\('D:/raxlarchitects/assets/index-BUkr1E8S.js', 'utf8'\);

// Try to parse and get more detailed error info
try {
  new vm.Script\(content\);
  console.log\('Syntax OK'\);
} catch \(e\) {
  console.log\('Error:', e.message\);

  // Try to find the error location
  const lines = content.split\('\\n'\);
  const errorLine = e.stack?.match\(/evalmachine.*:\(\\d+\):/\)?.[1];
  if \(errorLine\) {
    console.log\('Error at line:', errorLine\);
    if \(lines[errorLine - 1]\) {
      console.log\('Line content:', lines[errorLine - 1]\);
    }
  }

  // Look for common issues in the content
  const issues = [];

  // Check for backticks that might be problematic
  const backtickMatches = content.match\(/`[^`]*`/g\);
  if \(backtickMatches\) {
    for \(let i = 0; i < Math.min\(backtickMatches.length, 10\); i++\) {
      const m = backtickMatches[i];
      if \(m.includes\('\\n'\) || m.includes\('\\r'\)\) {
        issues.push\('Multiline template string at index ' + content.indexOf\(m\)\);
      }
    }
  }

  // Check for unmatched brackets/braces
  const openBraces = \(content.match\(/\\{/g\) || []\).length;
  const closeBraces = \(content.match\(/\\}/g\) || []\).length;
  const openBrackets = \(content.match\(/\\\(/g\) || []\).length;
  const closeBrackets = \(content.match\(/\\\)/g\) || []\).length;
  const openSquare = \(content.match\(/\\[/g\) || []\).length;
  const closeSquare = \(content.match\(/\\]/g\) || []\).length;

  console.log\('Bracket balance:'\);
  console.log\('  {}: ' + openBraces + ' vs ' + closeBraces + \(openBraces !== closeBraces ? ' MISMATCH!' : ''\)\);
  console.log\('  \(\): ' + openBrackets + ' vs ' + closeBrackets + \(openBrackets !== closeBrackets ? ' MISMATCH!' : ''\)\);
  console.log\('  []: ' + openSquare + ' vs ' + closeSquare + \(openSquare !== closeSquare ? ' MISMATCH!' : ''\)\);
}
EOF)

