const fs = require\('fs'\);

const content = fs.readFileSync\('D:/raxlarchitects/assets/index-git-version.js', 'utf8'\);

// Fix Chinese quotes first
let fixed = content.replace\(/\\u201C/g, '"'\).replace\(/\\u201D/g, '"'\);

// Fix the problematic template string escape sequences
// Inside template literals, \\" should become '
const pattern = /`[^`]*\\${[^}]*\\\\\\"[^}]*}[^`]*`/g;
fixed = fixed.replace\(pattern, \(match\) => {
  return match.replace\(/\\\\"/g, "'"\);
}\);

fs.writeFileSync\('D:/raxlarchitects/assets/index-BUkr1E8S.js', fixed, 'utf8'\);

console.log\('Fixed. Size:', fixed.length, 'characters'\);
